def solve(weight_kg: float):
    # Step 1: compute_daily_fluid_requirement
    # Apply the Holliday-Segar formula to calculate daily maintenance fluid in mL based on weight.
    if weight_kg <= 10:
        daily_fluid_ml = weight_kg * 100
    elif weight_kg <= 20:
        daily_fluid_ml = 1000 + (weight_kg - 10) * 50
    else:
        daily_fluid_ml = 1500 + (weight_kg - 20) * 20
        if daily_fluid_ml > 2400:
            daily_fluid_ml = 2400

    yield {
        "step_name": "compute_daily_fluid_requirement",
        "step_description": "Apply the Holliday-Segar formula to calculate daily maintenance fluid in mL based on weight.",
        "step_result": daily_fluid_ml,
        "unit": "mL"
    }

    return daily_fluid_ml
